# @cctt_verify {"v":2,"sym":"sympy.polys.tests.test_subresultants_qq_zz.test_sylvester","kind":"function","src_hash":"d620cb32a56f2daa","in":{"base":"Any"},"out":{"base":"Any","pred":"sylvester(x ** 3 - 7, 0, x) == sylvester(x ** 3 - 7, 0, x, 1) == Matrix([[0]]) and sylvester(0, x ** 3 - 7, x) == sylvester(0, x ** 3 - 7, x, 1) == Matrix([[0]]) and sylvester(x ** 3 - 7, 0, x, 2) == Matrix([[0]]) and sylvester(0, x ** 3 - 7, x, 2) == Matrix([[0]]) and sylvester(x ** 3 - 7, 7, x, 2).det() == -343 and sylvester(7, x ** 3 - 7, x, 2).det() == 343"},"spec":{"lhs":"test_sylvester()","rhs":"test_sylvester produces the expected output","over":{"base":"Any"},"name":"test_sylvester_correct"},"guarantee":"test_sylvester produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.polys.tests.test_subresultants_qq_zz.test_sylvester_correct","statement":"Path(test_sylvester(x), test_sylvester produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"46005fb1a849f2ce"}
def test_sylvester():
    x = Symbol('x')

    assert sylvester(x**3 -7, 0, x) == sylvester(x**3 -7, 0, x, 1) == Matrix([[0]])
    assert sylvester(0, x**3 -7, x) == sylvester(0, x**3 -7, x, 1) == Matrix([[0]])
    assert sylvester(x**3 -7, 0, x, 2) == Matrix([[0]])
    assert sylvester(0, x**3 -7, x, 2) == Matrix([[0]])

    assert sylvester(x**3 -7, 7, x).det() == sylvester(x**3 -7, 7, x, 1).det() == 343
    assert sylvester(7, x**3 -7, x).det() == sylvester(7, x**3 -7, x, 1).det() == 343
    assert sylvester(x**3 -7, 7, x, 2).det() == -343
    assert sylvester(7, x**3 -7, x, 2).det() == 343

    assert sylvester(3, 7, x).det() == sylvester(3, 7, x, 1).det() == sylvester(3, 7, x, 2).det() == 1

    assert sylvester(3, 0, x).det() == sylvester(3, 0, x, 1).det() == sylvester(3, 0, x, 2).det() == 1

    assert sylvester(x - 3, x - 8, x) == sylvester(x - 3, x - 8, x, 1) == sylvester(x - 3, x - 8, x, 2) == Matrix([[1, -3], [1, -8]])

    assert sylvester(x**3 - 7*x + 7, 3*x**2 - 7, x) == sylvester(x**3 - 7*x + 7, 3*x**2 - 7, x, 1) == Matrix([[1, 0, -7,  7,  0], [0, 1,  0, -7,  7], [3, 0, -7,  0,  0], [0, 3,  0, -7,  0], [0, 0,  3,  0, -7]])

    assert sylvester(x**3 - 7*x + 7, 3*x**2 - 7, x, 2) == Matrix([
[1, 0, -7,  7,  0,  0], [0, 3,  0, -7,  0,  0], [0, 1,  0, -7,  7,  0], [0, 0,  3,  0, -7,  0], [0, 0,  1,  0, -7,  7], [0, 0,  0,  3,  0, -7]])

